// Declare logger (Lombok: use @Slf4j on the class)
private static final Logger log = LoggerFactory.getLogger(OrderService.class);

// Parameterised logging — string only built if DEBUG is enabled
log.debug("Processing order {} for customer {}", orderId, customerId);

// String concatenation is wasteful — always built regardless of level:
log.debug("Processing order " + orderId + " for customer " + customerId); // BAD

// Exception logging — always include the exception as last argument
try {
    payment.charge(order);
} catch (PaymentException e) {
    log.error("Payment failed for order {}", order.getId(), e); // e = stack trace
}

// MDC (Mapped Diagnostic Context) — thread-local context added to every log line
MDC.put("userId", String.valueOf(userId));
MDC.put("requestId", UUID.randomUUID().toString());
try {
    processOrder(order); // all logs within include userId and requestId
} finally {
    MDC.clear(); // MUST clear — threads are reused in pools
}

