// 1. Generate or forward correlation ID at the entry point
@Component
public class CorrelationIdFilter extends OncePerRequestFilter {
    @Override
    protected void doFilterInternal(HttpServletRequest req,
                                    HttpServletResponse res,
                                    FilterChain chain) throws IOException, ServletException {
        String id = Optional.ofNullable(req.getHeader("X-Correlation-ID"))
            .orElse(UUID.randomUUID().toString());
        MDC.put("correlationId", id);
        res.addHeader("X-Correlation-ID", id); // echo back to client
        try {
            chain.doFilter(req, res);
        } finally {
            MDC.remove("correlationId");
        }
    }
}

// 2. Propagate to downstream HTTP calls
@Bean
public RestTemplate restTemplate() {
    RestTemplate rt = new RestTemplate();
    rt.getInterceptors().add((request, body, execution) -> {
        String id = MDC.get("correlationId");
        if (id != null) request.getHeaders().add("X-Correlation-ID", id);
        return execution.execute(request, body);
    });
    return rt;
}

// 3. For async (CompletableFuture / @Async): copy MDC to child thread
Map<String, String> ctx = MDC.getCopyOfContextMap();
CompletableFuture.runAsync(() -> {
    MDC.setContextMap(ctx);
    try { processAsync(); } finally { MDC.clear(); }
});

// Spring Boot Actuator auto-exposes /actuator/prometheus
// pom.xml: micrometer-registry-prometheus

@Service
public class OrderService {
    private final Counter ordersPlaced;
    private final Timer checkoutDuration;
    private final AtomicInteger activeCheckouts;

    public OrderService(MeterRegistry registry) {
        this.ordersPlaced = Counter.builder("orders.placed")
            .description("Total orders placed")
            .tag("region", "eu-west")
            .register(registry);

        this.checkoutDuration = Timer.builder("checkout.duration")
            .description("Time to complete checkout")
            .publishPercentiles(0.5, 0.95, 0.99) // p50, p95, p99
            .register(registry);

        Gauge.builder("checkouts.active", activeCheckouts, AtomicInteger::get)
            .description("Currently in-flight checkouts")
            .register(registry);
    }

    public Order placeOrder(Cart cart) {
        activeCheckouts.incrementAndGet();
        return checkoutDuration.record(() -> {
            Order order = doCheckout(cart);
            ordersPlaced.increment();
            return order;
        });
    }
}

